func deprecationLogLevelFromVersion(ver string) logg.Level {
	from := MustParseVersion(ver)
	to := CurrentVersion
	minorDiff := to.Minor - from.Minor
	switch {
	case minorDiff >= 12:

		return logg.LevelError
	case minorDiff >= 6:

		return logg.LevelWarn
	default:
		return logg.LevelInfo
	}
}
